'use client';

import { useRouter } from 'next/navigation';
import { ArrowLeft } from 'lucide-react';

type BackButtonProps = {
  className?: string;
};

export default function BackButton({ className = '' }: BackButtonProps) {
  const router = useRouter();

  return (
    <button
      type="button"
      onClick={() => router.back()}
      className={`inline-flex items-center gap-2 rounded-xl border border-palmier/20 bg-white/80 px-4 py-2.5 text-sm font-medium text-palmier transition hover:bg-palmier/5 hover:border-palmier/40 ${className}`}
    >
      <ArrowLeft size={18} />
      Retour
    </button>
  );
}
